const response = $input.first().json;
const statusCode = response.statusCode || 200;
const body = response.body;
const webhookData = $('Webhook Trigger').first().json.body || {};

if (statusCode >= 400) {
  return [{
    json: {
      error: true,
      message: `OpenAI embedding failed: ${statusCode}`,
      details: body
    }
  }];
}

let embedding = null;
try {
  if (body && body.data && body.data[0] && body.data[0].embedding) {
    embedding = body.data[0].embedding;
  }
} catch (e) {
  return [{
    json: {
      error: true,
      message: 'Failed to extract embedding'
    }
  }];
}

return [{
  json: {
    embedding: embedding,
    match_threshold: webhookData.match_threshold || 0.35,
    match_count: webhookData.match_count || 8,
    original_query: webhookData.query || ''
  }
}];

const response = $input.first().json;
const statusCode = response.statusCode || 200;
const body = response.body;
const originalQuery = $('Extract Embedding').first().json.original_query;

if (statusCode >= 400) {
  return [{
    json: {
      success: false,
      error: `Supabase search failed: ${statusCode}`,
      details: body,
      tool: 'semantic_search',
      query: originalQuery
    }
  }];
}

let memories = [];
try {
  if (typeof body === 'string') {
    memories = JSON.parse(body);
  } else if (Array.isArray(body)) {
    memories = body;
  } else if (body && typeof body === 'object') {
    memories = body.data || body.memories || [body];
  }
} catch (e) {
  memories = [];
}

const formatted = memories.map(m => ({
  id: m.id,
  title: m.title,
  summary: m.summary,
  transcript_excerpt: m.transcript ? m.transcript.substring(0, 500) + '...' : null,
  source: m.source,
  created_at: m.created_at,
  similarity: m.similarity ? (m.similarity * 100).toFixed(1) + '%' : null
}));

return [{
  json: {
    success: true,
    count: formatted.length,
    query: originalQuery,
    memories: formatted,
    tool: 'semantic_search',
    message: formatted.length > 0 
      ? `Found ${formatted.length} memories matching "${originalQuery}"` 
      : `No memories found matching "${originalQuery}". Try different search terms or use Search by Theme for broader results.`
  }
}];
